				AND reg_dat = #{regDat}



				AND doc_file_nm = #{docFileNm}



				AND doc_file_path = #{docFilePath}



				AND doc_no LIKE '%'||#{docNo}||'%'



                AND reg_dat  >=  #{startDat}



                AND reg_dat  <=  #{endDat}






				${sortCol} ${sortTyp}


				mgr_seq DESC




